TITLE = '国内旅行先診断【無料】あなたにぴったりの旅行スタイルが分かる'
DESCRIPTION = '好みのアクティビティ・予算・人数から最適な国内旅行先を無料診断。一人旅・カップル・家族旅行対応。'
JS_CODE = 'var Qs = [\n  { text:"旅行スタイルは？", opts:["のんびりリラックス","アクティブ・体験型","グルメ・食文化","文化・歴史・観光"], key:"style" },\n  { text:"誰と旅行しますか？", opts:["一人旅","カップル・夫婦","家族（子ども連れ）","友人グループ"], key:"companion" },\n  { text:"旅行予算（1人あたり）は？", opts:["1〜2万円","3〜5万円","6〜10万円","10万円以上"], key:"budget" },\n  { text:"好きな季節・時期は？", opts:["春（桜・花）","夏（海・祭り）","秋（紅葉・食）","冬（雪・温泉）"], key:"season" },\n  { text:"移動距離の希望は？", opts:["近場（日帰り〜1泊）","2〜3時間以内","遠くてもOK（4時間以上）"], key:"distance" }\n];\nvar cur=0,ans={};\n\nvar destinations = {\n  relax: [\n    { name:"草津温泉（群馬）", emoji:"♨️", desc:"日本三名泉の一つ。湯畑を中心とした温泉街で心身ともにリフレッシュ。", tag:"温泉・湯治" },\n    { name:"別府温泉（大分）", emoji:"♨️", desc:"湧出量日本一の温泉地。地獄めぐりやBEPPU PROJECTも人気。", tag:"温泉・文化" },\n    { name:"伊豆（静岡）", emoji:"🌊", desc:"海と山の両方を楽しめる関東随一のリゾートエリア。", tag:"温泉・海鮮" }\n  ],\n  active: [\n    { name:"沖縄（本島・離島）", emoji:"🤿", desc:"シュノーケリング・ダイビング・マリンスポーツを満喫。離島での非日常体験も。", tag:"マリンスポーツ" },\n    { name:"北海道（ニセコ・富良野）", emoji:"⛷️", desc:"夏はトレッキング、冬はスキー。雄大な自然でアウトドアを満喫。", tag:"アウトドア" },\n    { name:"屋久島（鹿児島）", emoji:"🌳", desc:"世界自然遺産の屋久島。縄文杉トレッキングで大自然を体感。", tag:"トレッキング" }\n  ],\n  gourmet: [\n    { name:"京都・大阪（関西）", emoji:"🍱", desc:"京料理・大阪グルメを両方楽しめる。食い倒れツアーの定番。", tag:"和食・B級グルメ" },\n    { name:"福岡", emoji:"🍜", desc:"博多ラーメン・もつ鍋・屋台文化。コンパクトな都市で食べ歩きに最適。", tag:"博多グルメ" },\n    { name:"金沢（石川）", emoji:"🦀", desc:"日本海の新鮮な魚介・加賀料理。近江町市場で旬の味覚を堪能。", tag:"海鮮・加賀料理" }\n  ],\n  culture: [\n    { name:"京都", emoji:"⛩️", desc:"1200年の歴史が詰まった古都。寺社仏閣・伝統文化・舞妓さんも。", tag:"歴史・伝統文化" },\n    { name:"奈良", emoji:"🦌", desc:"東大寺・法隆寺・春日大社。鹿と触れ合いながら古代日本を散策。", tag:"古都・歴史" },\n    { name:"長崎", emoji:"🏯", desc:"異国情緒あふれる街並み。グラバー園・出島・眼鏡橋が見どころ。", tag:"異国情緒・歴史" }\n  ]\n};\n\nfunction startDiagnosis() { show(\'questions\'); renderQ(); }\n\nfunction show(name) {\n  document.querySelectorAll(\'.screen\').forEach(function(s){ s.classList.remove(\'active\'); });\n  document.getElementById(\'screen-\'+name).classList.add(\'active\');\n}\n\nfunction renderQ() {\n  var q=Qs[cur];\n  var pct=Math.round((cur+1)/Qs.length*100);\n  document.getElementById(\'q-label\').textContent=\'質問 \'+(cur+1)+\' / \'+Qs.length;\n  document.getElementById(\'q-pct\').textContent=pct+\'%\';\n  document.getElementById(\'prog\').style.width=pct+\'%\';\n  document.getElementById(\'q-text\').textContent=q.text;\n  var c=document.getElementById(\'opts\'); c.innerHTML=\'\';\n  q.opts.forEach(function(opt,i){\n    var b=document.createElement(\'button\');\n    b.className=\'option-btn\'; b.textContent=opt;\n    b.onclick=function(){ pick(i,opt,q.key); };\n    c.appendChild(b);\n  });\n}\n\nfunction pick(i,val,key) {\n  ans[key]={i:i,val:val};\n  document.querySelectorAll(\'.option-btn\').forEach(function(b,j){ b.classList.toggle(\'selected\',j===i); });\n  setTimeout(function(){\n    cur++;\n    if(cur<Qs.length){ renderQ(); } else { show(\'loading\'); setTimeout(showResults,1600); }\n  },300);\n}\n\nfunction showResults() {\n  var styleIdx = ans.style ? ans.style.i : 0;\n  var styleKeys = [\'relax\',\'active\',\'gourmet\',\'culture\'];\n  var styleLabels = [\'のんびりリラックス派\',\'アクティブ・体験派\',\'グルメ・食文化派\',\'文化・歴史派\'];\n  var key = styleKeys[styleIdx];\n  var dests = destinations[key];\n  document.getElementById(\'res-style\').textContent = styleLabels[styleIdx]+\'のあなたへのおすすめ\';\n  var list = document.getElementById(\'destinations-list\');\n  list.innerHTML = \'\';\n  dests.forEach(function(d,i){\n    var div = document.createElement(\'div\');\n    div.className = \'destination-card\';\n    div.innerHTML = \'<div class="flex items-center gap-2 mb-1"><span class="text-xl">\'+d.emoji+\'</span><div><div class="font-bold text-gray-800">\'+(i===0?\'🥇 \':\'\')+(i===1?\'🥈 \':\'\')+(i===2?\'🥉 \':\'\')+d.name+\'</div><span class="text-xs bg-sky-100 text-sky-700 px-2 py-0.5 rounded-full">\'+d.tag+\'</span></div></div><p class="text-sm text-gray-600">\'+d.desc+\'</p>\';\n    list.appendChild(div);\n  });\n  show(\'results\');\n}\n\nfunction restart() { cur=0; ans={}; show(\'intro\'); }'
